import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate a business loan payment?", a: "Use the standard amortized loan formula with principal, monthly interest rate, and number of monthly payments." },
  { q: "What is a good interest rate for a business loan?", a: "A good rate depends on credit, revenue, collateral, loan term, lender type, and market rates. Strong borrowers usually qualify for lower rates." },
  { q: "What is an SBA loan?", a: "An SBA loan is a small business loan partially guaranteed by the US Small Business Administration and issued by approved lenders." },
  { q: "How does a business line of credit work?", a: "A line of credit lets a business borrow up to a limit, repay, and borrow again. Interest usually applies only to the amount drawn." },
  { q: "What documents do you need for a business loan?", a: "Common documents include financial statements, tax returns, bank statements, business plans, ownership information, and debt schedules." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function payment(principal: number, apr: number, months: number) {
  const r = apr / 100 / 12;
  return r === 0 ? principal / months : principal * r / (1 - Math.pow(1 + r, -months));
}

function amortize(principal: number, apr: number, months: number) {
  const monthly = payment(principal, apr, months);
  let balance = principal;
  const schedule = [];
  for (let month = 1; month <= months && month <= 120; month++) {
    const interest = balance * apr / 100 / 12;
    const principalPaid = Math.min(balance, monthly - interest);
    balance = Math.max(0, balance - principalPaid);
    schedule.push({ month, payment: monthly, principal: principalPaid, interest, balance });
  }
  return schedule;
}

export default function BusinessLoanCalculator() {
  useCurrencyVersion();
  const [amount, setAmount] = useState(100000);
  const [rate, setRate] = useState(8);
  const [term, setTerm] = useState(60);
  const [fee, setFee] = useState(2);

  const result = useMemo(() => {
    const monthly = payment(amount, rate, term);
    const totalInterest = monthly * term - amount;
    const feeAmount = amount * fee / 100;
    const netProceeds = Math.max(1, amount - feeAmount);
    const trueApr = ((monthly * term - netProceeds) / netProceeds) / (term / 12) * 100;
    return { monthly, totalInterest, feeAmount, trueApr, schedule: amortize(amount, rate, term) };
  }, [amount, rate, term, fee]);
  const amounts = [25000, 50000, 100000, 250000, 500000];

  return (
    <>
      <SEOHead title="Free Business Loan Calculator Online - Calculate Business Loan Payments Instantly | CalcHive" description="Free online business loan calculator. Calculate monthly business loan payments, total interest, true APR with fees and amortization schedule instantly. 100% free, no signup required." canonical="/business-loan-calculator" keywords="free business loan calculator, small business loan calculator free online, commercial loan calculator free, calculate business loan payment free, SBA loan calculator free online" category="Financial Calculators" breadcrumbName="Free Business Loan Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Business Loan Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate small business loan payments, total interest, true APR with fees, and amortization.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Loan amount</label><input type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Loan term months</label><input type="number" value={term} onChange={(e) => setTerm(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Origination fee (%)</label><input type="number" value={fee} onChange={(e) => setFee(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{money(result.totalInterest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Origination fee</p><p className="text-lg font-extrabold text-foreground">{money(result.feeAmount)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">APR with fees</p><p className="text-lg font-extrabold text-foreground">{pct(result.trueApr)}</p></div></div>
          <div className="overflow-x-auto mt-5"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Amortization Schedule</caption><thead className="bg-muted/60"><tr>{["Month", "Payment", "Principal", "Interest", "Balance"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.schedule.map((row) => <tr key={row.month}><td className="py-2.5 px-3">{row.month}</td><td className="py-2.5 px-3">{money(row.payment)}</td><td className="py-2.5 px-3">{money(row.principal)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Business Loan Payments for Free</h2><p className="text-muted-foreground leading-relaxed">Business loan payments depend on loan amount, annual rate, loan term, and any upfront fees that affect true borrowing cost.</p>
          <h2 className="text-2xl font-bold text-foreground">How Origination Fees Affect Your True Business Loan Cost</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Business Loan Monthly Payment by Amount and Rate</caption><thead className="bg-muted/60"><tr>{["Loan Amount", "6% Rate 3yr", "8% Rate 3yr", "10% Rate 5yr", "12% Rate 5yr"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{amounts.map((a) => <tr key={a}><td className="py-2.5 px-3 font-semibold">{money(a, 0)}</td><td className="py-2.5 px-3">{money(payment(a, 6, 36))}</td><td className="py-2.5 px-3">{money(payment(a, 8, 36))}</td><td className="py-2.5 px-3">{money(payment(a, 10, 60))}</td><td className="py-2.5 px-3">{money(payment(a, 12, 60))}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Small Business Loan Payment Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this commercial loan calculator for term loans, equipment financing, SBA-style estimates, and repayment planning.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/business-loan-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


